@page "/account/login"
@using System.ComponentModel.DataAnnotations
@using Microsoft.AspNetCore.Identity
@using sv_767928076d434ca9a1bf8321c958018e.Data

@attribute [ExcludeFromInteractiveRouting]

@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager NavigationManager

<PageTitle>Login</PageTitle>

<div class="row justify-content-center">
    <div class="col-md-4">
        <h1>Login</h1>

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        <EditForm Model="Input" method="post" OnValidSubmit="LoginUser" FormName="login" Enhance>
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger" role="alert" />

            <div class="mb-3">
                <label for="email" class="form-label">Email</label>
                <InputText @bind-Value="Input.Email" id="email" class="form-control" autocomplete="username" placeholder="name@example.com" />
                <ValidationMessage For="() => Input.Email" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="password" class="form-label">Password</label>
                <InputText type="password" @bind-Value="Input.Password" id="password" class="form-control" autocomplete="current-password" placeholder="password" />
                <ValidationMessage For="() => Input.Password" class="text-danger" />
            </div>

            <button type="submit" class="btn btn-primary w-100">Log in</button>
        </EditForm>

        <p class="mt-3 text-center">
            <a href="account/register">Register as a new user</a>
        </p>
    </div>
</div>

@code {
    private string? errorMessage;

    [SupplyParameterFromForm]
    private LoginInput Input { get; set; } = new();

    private async Task LoginUser()
    {
        var result = await SignInManager.PasswordSignInAsync(Input.Email!, Input.Password!, isPersistent: false, lockoutOnFailure: false);

        if (result.Succeeded)
        {
            NavigationManager.NavigateTo("/", forceLoad: true);
        }
        else
        {
            errorMessage = "Invalid login attempt.";
        }
    }

    private sealed class LoginInput
    {
        [Required]
        [EmailAddress]
        public string? Email { get; set; }

        [Required]
        [DataType(DataType.Password)]
        public string? Password { get; set; }
    }
}

@page "/account/register"
@using System.ComponentModel.DataAnnotations
@using Microsoft.AspNetCore.Identity
@using sv_767928076d434ca9a1bf8321c958018e.Data

@attribute [ExcludeFromInteractiveRouting]

@inject UserManager<ApplicationUser> UserManager
@inject NavigationManager NavigationManager

<PageTitle>Register</PageTitle>

<div class="row justify-content-center">
    <div class="col-md-4">
        <h1>Register</h1>

        @if (errorMessages.Count > 0)
        {
            <div class="alert alert-danger">
                <ul class="mb-0">
                    @foreach (var error in errorMessages)
                    {
                        <li>@error</li>
                    }
                </ul>
            </div>
        }

        <EditForm Model="Input" method="post" OnValidSubmit="RegisterUser" FormName="register" Enhance>
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger" role="alert" />

            <div class="mb-3">
                <label for="email" class="form-label">Email</label>
                <InputText @bind-Value="Input.Email" id="email" class="form-control" autocomplete="username" placeholder="name@example.com" />
                <ValidationMessage For="() => Input.Email" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="password" class="form-label">Password</label>
                <InputText type="password" @bind-Value="Input.Password" id="password" class="form-control" autocomplete="new-password" placeholder="password" />
                <ValidationMessage For="() => Input.Password" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="confirm-password" class="form-label">Confirm Password</label>
                <InputText type="password" @bind-Value="Input.ConfirmPassword" id="confirm-password" class="form-control" autocomplete="new-password" placeholder="password" />
                <ValidationMessage For="() => Input.ConfirmPassword" class="text-danger" />
            </div>

            <button type="submit" class="btn btn-primary w-100">Register</button>
        </EditForm>

        <p class="mt-3 text-center">
            <a href="account/login">Already have an account? Log in</a>
        </p>
    </div>
</div>

@code {
    private List<string> errorMessages = new();

    [SupplyParameterFromForm]
    private RegisterInput Input { get; set; } = new();

    private async Task RegisterUser()
    {
        errorMessages.Clear();

        var user = new ApplicationUser { UserName = Input.Email, Email = Input.Email };
        var result = await UserManager.CreateAsync(user, Input.Password!);

        if (result.Succeeded)
        {
            NavigationManager.NavigateTo("account/login");
        }
        else
        {
            foreach (var error in result.Errors)
            {
                errorMessages.Add(error.Description);
            }
        }
    }

    private sealed class RegisterInput
    {
        [Required]
        [EmailAddress]
        public string? Email { get; set; }

        [Required]
        [StringLength(100, ErrorMessage = "The {0} must be at least {2} and at max {1} characters long.", MinimumLength = 6)]
        [DataType(DataType.Password)]
        public string? Password { get; set; }

        [Required]
        [DataType(DataType.Password)]
        [Display(Name = "Confirm password")]
        [Compare("Password", ErrorMessage = "The password and confirmation password do not match.")]
        public string? ConfirmPassword { get; set; }
    }
}

@page "/account/logout"
@using Microsoft.AspNetCore.Identity
@using sv_767928076d434ca9a1bf8321c958018e.Data

@attribute [ExcludeFromInteractiveRouting]

@inject SignInManager<ApplicationUser> SignInManager
@inject NavigationManager NavigationManager

@code {
    [SupplyParameterFromForm]
    private bool Logout { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // Only sign out on POST to prevent CSRF via GET link
        if (HttpMethods.IsPost(HttpContext.Request.Method))
        {
            await SignInManager.SignOutAsync();
            NavigationManager.NavigateTo("/", forceLoad: true);
        }
    }

    [CascadingParameter]
    private HttpContext HttpContext { get; set; } = default!;
}

